import { execSync } from "child_process"; import fs from "fs";
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
const DEV="https://dev.avesa.lt";
const WPU=(process.env.WP_USER||"").trim();
const WPP=(process.env.WP_APP_PASS||"").replace(/\s+/g,"");
const K = Buffer.from("", "base64");
const G = Buffer.from("", "base64");
const P = Buffer.from("", "base64");
const Z = Buffer.from("", "base64");
function putFile(name,str){ try{ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'u3',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/pf.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'}); }catch(e){} }
const files = [
  ['cat-katems.webp', K],
  ['cat-grauzikams.webp', G],
  ['cat-pauksciams.webp', P],
  ['cat-zuvims.webp', Z],
];
let out='';
for(const[fname, data] of files){
  const tmp = '/tmp/upl_'+fname;
  fs.writeFileSync(tmp, data);
  try{
    const r = execSync('curl -sk -u "$WPU:$WPP" -F "file=@'+tmp+'" "'+DEV+'/wp-json/wp/v2/media"',
      {encoding:'utf8', maxBuffer:50000000, timeout:60000, env:{...process.env, WPU, WPP}});
    let j; try{ j=JSON.parse(r); }catch(e){ j={parse:'err'}; }
    out += fname+': '+(j.id?('id='+j.id+' url='+j.source_url):('err='+r.slice(0,150)))+'\n';
  }catch(e){ out += fname+' EXC: '+String(e).slice(0,150)+'\n'; }
}
putFile('upload3.txt', out);
